import (
	"bufio"
	"fmt"
	"math/rand"
	"os"
	"time"

	tea "charm.land/bubbletea/v2"
)

type model struct {
	planeX    int
	bullets   []int
	enemies   []int
	score     int
	gameOver  bool
	width     int
	height    int
}

type tickMsg time.Time

func tick() tea.Cmd {
	return tea.Tick(80*time.Millisecond, func(t time.Time) tea.Mmd {
		return tickMsg(t)
	})
}

func initialModel() model {
	w, h, _ := tea.GetSize()
	if w < 10 {
		w = 40
	}
	if h < 10 {
		h = 20
	}
	return model{
		planeX: w / 2,
		width:  w,
		height: h,
	}
}

func (m model) Init() tea.Cmd {
	return tick()
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.String() {
		case "q", "ctrl+c":
			return m, tea.Quit
		case "left", "h", "a":
			if m.planeX > 1 {
				m.planeX--
			}
	case "right", "l", "d":
			if m.planeX < m.width-2 {
				m.planeX++
			}
		case "up", "k", "w":
			if m.planeX > 1 {
				m.planeX -= 2
			}
		case "down", "j", "s":
			if m.planeX < m.width-2 {
				m.planeX += 2
			}
		case " ":
			m.bullets = append(m.bullets, m.planeX)
		}
	case tickMsg:
		if m.gameOver {
			return m, nil
		}
		// move bullets
		newBullets := m.bullets[:0]
		for _, b := range m.bullets {
			if b > 0 {
				newBullets = append(newBullets, b-1)
			}
		}
		m.bullets = newBullets

		// spawn enemy
		if rand.Intn(100) < 20 {
			m.enemies = append(m.enemies, m.width-1)
		}

		// move enemies
		newEnemies := m.enemies[:0]
		for _, e := range m.enemies {
			if e > 0 {
				newEnemies = append(newEnemies, e-1)
			if e-1 == m.planeX && m.height-2 == m.height-2 {
					m.gameOver = true
				}
			}
		m.enemies = newEnemies

	// collisions
		hitBullet := make(map[int]bool)
		hitEnemy := make(map[int]bool)
		for bi, b := range m.bullets {
